Actionscript.script:
空手攻击搓招 = _root.技能函数.空手攻击搓招;
诛杀步可派生搓招 = _root.技能函数.诛杀步可派生搓招;
后撤步可派生搓招 = _root.技能函数.后撤步可派生搓招;
波动拳可派生搓招 = _root.技能函数.波动拳可派生搓招;
能量喷泉可派生搓招 = _root.技能函数.能量喷泉可派生搓招;
燃烧指节可派生搓招 = _root.技能函数.燃烧指节可派生搓招;

空手攻击搓招 = _root.技能函数.空手攻击搓招;
诛杀步可派生搓招 = _root.技能函数.诛杀步可派生搓招;
后撤步可派生搓招 = _root.技能函数.后撤步可派生搓招;
波动拳可派生搓招 = _root.技能函数.波动拳可派生搓招;
能量喷泉可派生搓招 = _root.技能函数.能量喷泉可派生搓招;
燃烧指节可派生搓招 = _root.技能函数.燃烧指节可派生搓招;
连环踢可派生搓招 = _root.技能函数.连环踢可派生搓招;
回旋踢可派生搓招 = _root.技能函数.回旋踢可派生搓招;

function 消弹()
{
	var 消弹属性 = _root.消弹属性初始化(this.攻击点);
	消弹属性.消弹方向 = _parent.方向 == "右" ? "左" : "右";
	消弹属性.Z轴攻击范围 = 30;
	消弹属性.区域定位area = this.攻击点;

	_root.消除子弹(消弹属性);
}

onClipEvent (enterFrame) {
	if (_parent._parent._name == _root.控制目标)
	{
		_parent.空手攻击搓招();
	}
	_parent.变招判定("破极拳2连招");
}

onClipEvent (enterFrame) {
	if (_parent._parent._name == _root.控制目标)
	{
		_parent.空手攻击搓招();
	}
	_parent.变招判定("破极拳3连招");
}

onClipEvent (enterFrame) {
	if (_parent._parent._name == _root.控制目标)
	{
		_parent.空手攻击搓招();
	}
	_parent.变招判定("破极拳4连招");
}

onClipEvent (enterFrame) {
	if (_parent._parent._name == _root.控制目标)
	{
		_parent.空手攻击搓招();
	}
	_parent.变招判定("破极拳5连招");
}

onClipEvent (enterFrame) {
	if (_parent._parent._name == _root.控制目标)
	{
		// 统一走搓招函数（支持DFA预输入）
		_root.技能函数.使用后撤步() || _root.技能函数.使用波动拳();
	}
}

function 消弹()
{
	var 消弹属性 = _root.消弹属性初始化(this.攻击点);
	消弹属性.消弹方向 = _parent.方向 == "右" ? "左" : "右";
	消弹属性.Z轴攻击范围 = 30;
	消弹属性.区域定位area = this.攻击点;

	_root.消除子弹(消弹属性);
}

持续帧 = 10;
扭转乾坤恢复 = _root.技能函数.扭转乾坤恢复;
_root.技能函数.扭转乾坤护盾释放(_parent,_parent.技能等级);
许可 = true;

if (_parent.hp + 20 < _parent.hp满血值 * 1.5)
{
	_parent.hp += 20;
}
if (_parent.mp + 30 + Math.ceil(_parent.mp满血值 * 0.01) < _parent.mp满血值)
{
	_parent.mp += 30 + Math.ceil(_parent.mp满血值 * 0.01);
}else{
	_parent.mp =  _parent.mp满血值;
}

持续帧 += 20;
if(_parent.技能等级 && 持续帧 < 30 + _parent.技能等级 * 12){
	gotoAndPlay("循环");
}

if (_parent.被动技能.内力爆发 && _parent.被动技能.内力爆发.启用 && _parent.hp > 10 && _parent.mp > 10)
{
	_parent.hp -= 10;
	_parent.mp -= 10;
	var 恢复值 = _parent.内力 * (10 + _parent.被动技能.内力爆发.等级) / 10;
	//_parent.mp += _parent.内力 * ( 10 + _parent.被动技能.内力爆发.等级) / 20;
	var effects = [{type:"regen", hp:恢复值, mp:恢复值, duration:150, interval:30, mode:"total", id:"内力周转_缓释_聚气", scaleWithAlchemy:false}];
	_root.释放药剂效果(_parent,effects)
}
_root.播放音效("龙斩1.wav");

onClipEvent(load){
	子弹属性 = _root.子弹属性初始化(this);

	//以下部分只需要更改需要更改的属性,其余部分可注释掉
	子弹属性.声音 = "";
	子弹属性.霰弹值 = 1;
	子弹属性.子弹散射度 = 0;
	子弹属性.子弹种类 = "近战子弹";
	子弹属性.子弹威力 =  _parent._parent.空手攻击力;
	if (_parent._parent.被动技能.拳脚攻击 && _parent._parent.被动技能.拳脚攻击.启用)
	{
		子弹属性.子弹威力 *= 1 + _parent._parent.被动技能.拳脚攻击.等级 * 0.1;
	}
	if(_parent._parent.mp攻击加成){
		子弹属性.子弹威力 += _parent._parent.mp攻击加成;
	}
	子弹属性.子弹速度 = 0;
	子弹属性.Z轴攻击范围 = 30;
	子弹属性.击倒率 = 1;

	子弹属性.水平击退速度 = 7;
	//非常用
	/*
	子弹属性.垂直击退速度 = NaN;
	子弹属性.发射效果 = "";
	子弹属性.击中地图效果 = "火花".
	子弹属性.击中后子弹的效果 = "".
	子弹属性.命中率 = NaN.
	子弹属性.固伤 = NaN;
	子弹属性.百分比伤害 = NaN;
	子弹属性.血量上限击溃 = NaN;
	子弹属性.防御粉碎 = NaN;
	*/
	子弹属性.区域定位area = this.area;
	/*
	//已初始化内容，通常不需要重复赋值，可注释掉
	子弹属性.发射者 = 子弹属性.发射者.
	子弹属性.shootX = 子弹属性.shootX;
	子弹属性.shootY = 子弹属性.shootY;
	子弹属性.shootZ = 子弹属性.shootZ;
	子弹属性.子弹敌我属性 = 子弹属性.子弹敌我属性;
	*/
	_root.子弹区域shoot传递(子弹属性);
}

